mapper.select:
SELECT DISTINCT rs.* FROM retired_staff rs

    LEFT JOIN staff_relative sr ON rs.staff_id = sr.staff_id



        AND rs.real_name LIKE CONCAT('%', #{realName}, '%')


        AND rs.former_dept LIKE CONCAT('%', #{formerDept}, '%')


        AND rs.job_title LIKE CONCAT('%', #{jobTitle}, '%')


        AND rs.age >= #{ageMin}


        AND rs.age <= #{ageMax}


        AND rs.retire_date >= #{retireDateStart}


        AND rs.retire_date <= #{retireDateEnd}


        AND sr.name LIKE CONCAT('%', #{childName}, '%')
        AND sr.relation_type IN ('儿子', '女儿', '子女')


ORDER BY rs.staff_id DESC

mapper.update:
UPDATE retired_staff
real_name = #{realName}, photo = #{photo}, gender = #{gender}, id_card = #{idCard}, age = #{age}, nation = #{nation}, education = #{education}, native_place = #{nativePlace}, work_start_date = #{workStartDate}, retire_date = #{retireDate}, former_dept = #{formerDept}, job_title = #{jobTitle}, phone = #{phone},
WHERE staff_id = #{staffId}
